+export const OnboardingChecklist: React.FC<{ steps: OnboardingStep[] }> = ({ steps }) => {
+  const completed = steps.filter(s => s.completed).length;
+  return (
+    <Card className='onboarding-checklist'>
+      <h3>Get started ({completed}/{steps.length})</h3>
+      {steps.map(step => <ChecklistItem key={step.id} step={step} />)}
+    </Card>
+  );
+}

